import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/extension-view.BUCve89_.js";const s=JSON.parse(`{"title":"设置 VS Code","description":"有关如何搭建 Visual Studio Code 以使用 Fabric 创作模组的逐步指南。","frontmatter":{"title":"设置 VS Code","description":"有关如何搭建 Visual Studio Code 以使用 Fabric 创作模组的逐步指南。","authors":["dicedpixels"],"prev":{"text":"设置你的 IDE","link":"../setting-up"},"next":{"text":"在 VS Code 中打开项目","link":"./opening-a-project"},"files":[]},"headers":[],"relativePath":"zh_cn/develop/getting-started/vscode/setting-up.md","filePath":"translated/zh_cn/develop/getting-started/vscode/setting-up.md","lastUpdated":1770561656000}`);var c={name:`zh_cn/develop/getting-started/vscode/setting-up.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">设置 VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “设置 VS Code”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">重要</p><p>虽然使用 Visual Studio Code 开发模组是可行的，但是我们不推荐这样做。 建议使用 <a href="./../intellij-idea/setting-up">IntelliJ IDEA</a>，它拥有专门的 Java 工具链、高级功能和有用的社区创建插件，例如 <strong>Minecraft Development</strong>。</p></div><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>请确保先<a href="./../setting-up#install-jdk-21">安装 JDK</a>。</p></div><h2 id="installation" tabindex="-1">安装 <a class="header-anchor" href="#installation" aria-label="Permalink to “安装”">​</a></h2><p>你可以从 <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">code.visualstudio.com</a> 下载 Visual Studio Code，或通过您喜欢的包管理器进行下载。</p><p><img src="/assets/develop/getting-started/vscode/download.png" alt="Visual Studio Code 下载页" loading="lazy"></p><h2 id="prerequisites" tabindex="-1">前置条件 <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “前置条件”">​</a></h2><p>Visual Studio Code 本身不提供 Java 语言支持。 然而，Microsoft 提供了一个方便的扩展包，其中包含所有必要的扩展，以启用 Java 语言支持。</p><p>你可以从 <a href="https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack" target="_blank" rel="noreferrer">Visual Studio Marketplace</a> 安装这个扩展包。</p><p><img src="/assets/develop/getting-started/vscode/extension.png" alt="Java 扩展包" loading="lazy"></p><p>或者，你也可以在 Visual Studio Code 本身中，通过扩展视图来安装。</p><p><img src="/assets/develop/getting-started/vscode/extension-view.png" alt="扩展视图中的 Java 扩展包" loading="lazy"></p><p><strong>Language Support for Java</strong> 扩展会为你提供一个启动屏幕来设置 JDK。 如果你还没有设置，可以这样做。</p>`,13)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};